devHandoff.css:
.check path{stroke-dasharray:var(--len);stroke-dashoffset:var(--len);transition:stroke-dashoffset var(--motion-duration-base) var(--motion-ease-smooth)}
input:checked+.box .check path{stroke-dashoffset:0}
.box{transition:background-color var(--motion-duration-base) var(--motion-ease-smooth)}

.t-morph{position:relative;width:44px;height:44px;border-radius:40px;overflow:hidden;transition:width 250ms var(--morph-close-ease),height 250ms var(--morph-close-ease),border-radius 250ms var(--morph-close-ease)}
.t-morph[data-open=true]{width:208px;height:150px;border-radius:12px;transition:width 350ms var(--morph-ease),height 350ms var(--morph-ease),border-radius 350ms var(--morph-ease)}
.t-morph-menu{position:absolute;inset:0;opacity:0;transform:translateX(40px) scale(0.97);filter:blur(2px);transition:opacity 200ms,transform 350ms,filter 200ms}
.t-morph[data-open=true] .t-morph-menu{opacity:1;transform:none;filter:blur(0)}
